// src/pages/admin/AdminDashboard.js
import React, { useEffect, useState } from "react";
import { Paper, Typography, Grid, Card, CardContent, Table, TableHead, TableRow, TableCell, TableBody, Button, IconButton } from "@mui/material";
import { People, DirectionsBike, CheckCircle, HourglassEmpty, LocalTaxi, Visibility, Download } from "@mui/icons-material";
import { getOverview, getUsers, getRiders, getApprovedCaptains, getPendingCaptains, getRides, approveCaptain, rejectCaptain } from "../../services/adminApi";

export default function AdminDashboard() {
  const [overview, setOverview] = useState({});
  const [activeTable, setActiveTable] = useState("users"); // users, riders, approved, pending, rides
  const [tableData, setTableData] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchOverview = async () => {
    try {
      setLoading(true);
      const overviewRes = await getOverview();
      setOverview(overviewRes.data);
    } catch (err) {
      console.error("Overview fetch error:", err);
    } finally {
      setLoading(false);
    }
  };

  const fetchTableData = async (type) => {
    try {
      setLoading(true);
      let res;
      switch (type) {
        case "users":
          res = await getUsers();
          setTableData(res.data.users);
          break;
        case "riders":
          res = await getRiders();
          setTableData(res.data.riders);
          break;
        case "approved":
          res = await getApprovedCaptains();
          setTableData(res.data.captains);
          break;
        case "pending":
          res = await getPendingCaptains();
          setTableData(res.data.pendingCaptains);
          break;
        case "rides":
          res = await getRides();
          setTableData(res.data.rides);
          break;
        default:
          setTableData([]);
      }
    } catch (err) {
      console.error("Table data fetch error:", err);
      setTableData([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchOverview();
    fetchTableData(activeTable);
  }, [activeTable]);

  const handleApprove = async (id) => {
    await approveCaptain(id);
    fetchTableData("pending");
    fetchOverview();
  };

  const handleReject = async (id) => {
    await rejectCaptain(id);
    fetchTableData("pending");
    fetchOverview();
  };

  const overviewCards = [
    { label: "Users", value: overview.users, icon: <People />, type: "users" },
    { label: "Riders", value: overview.riders, icon: <DirectionsBike />, type: "riders" },
    { label: "Approved Captains", value: overview.captains, icon: <CheckCircle />, type: "approved" },
    { label: "Pending Captains", value: overview.pendingCaptains, icon: <HourglassEmpty />, type: "pending" },
    { label: "Total Rides", value: overview.rides, icon: <LocalTaxi />, type: "rides" },
  ];

  return (
    <div>
      <Typography variant="h4" gutterBottom>
        Admin Dashboard
      </Typography>

      <Grid container spacing={2} sx={{ mb: 3 }}>
        {overviewCards.map((card) => (
          <Grid item xs={12} sm={6} md={2.4} key={card.label}>
            <Card onClick={() => setActiveTable(card.type)} sx={{ cursor: "pointer" }}>
              <CardContent sx={{ display: "flex", alignItems: "center", gap: 2 }}>
                {card.icon}
                <div>
                  <Typography variant="h6">{card.value ?? 0}</Typography>
                  <Typography variant="body2">{card.label}</Typography>
                </div>
              </CardContent>
            </Card>
          </Grid>
        ))}
      </Grid>

      {loading ? (
        <Typography>Loading...</Typography>
      ) : tableData.length === 0 ? (
        <Typography>No data found.</Typography>
      ) : (
        <Paper sx={{ p: 2 }}>
          <Typography variant="h6" gutterBottom>
            {activeTable.charAt(0).toUpperCase() + activeTable.slice(1)}
          </Typography>
          <Table>
            <TableHead>
              <TableRow>
                {activeTable === "rides" ? (
                  <>
                    <TableCell>Rider</TableCell>
                    <TableCell>Captain</TableCell>
                    <TableCell>Pickup</TableCell>
                    <TableCell>Drop</TableCell>
                    <TableCell>Fare</TableCell>
                    <TableCell>Status</TableCell>
                  </>
                ) : (
                  <>
                    <TableCell>Name</TableCell>
                    <TableCell>Email</TableCell>
                    <TableCell>Mobile</TableCell>
                    <TableCell>Role</TableCell>
                    <TableCell>Login Count</TableCell>
                    <TableCell>Approval Status</TableCell>
                    {activeTable === "pending" && <TableCell>Actions</TableCell>}
                    {activeTable !== "pending" && <TableCell>Documents</TableCell>}
                  </>
                )}
              </TableRow>
            </TableHead>
            <TableBody>
              {tableData.map((row) => (
                <TableRow key={row._id}>
                  {activeTable === "rides" ? (
                    <>
                      <TableCell>{row.riderId?.fullName || "-"}</TableCell>
                      <TableCell>{row.captainId?.fullName || "-"}</TableCell>
                      <TableCell>{row.pickup}</TableCell>
                      <TableCell>{row.drop}</TableCell>
                      <TableCell>{row.fare}</TableCell>
                      <TableCell>{row.status}</TableCell>
                    </>
                  ) : (
                    <>
                      <TableCell>{row.fullName}</TableCell>
                      <TableCell>{row.email}</TableCell>
                      <TableCell>{row.mobile}</TableCell>
                      <TableCell>{row.role}</TableCell>
                      <TableCell>{row.loginCount}</TableCell>
                      <TableCell>{row.approvalStatus}</TableCell>
                      {activeTable === "pending" ? (
                        <TableCell>
                          <Button variant="contained" color="success" onClick={() => handleApprove(row._id)} sx={{ mr: 1 }}>
                            Approve
                          </Button>
                          <Button variant="contained" color="error" onClick={() => handleReject(row._id)}>
                            Reject
                          </Button>
                        </TableCell>
                      ) : (
                        <TableCell>
                          {row.documents?.length ? (
                            row.documents.map((doc, i) => (
                              <div key={i}>
                                <IconButton component="a" href={doc.url} target="_blank">
                                  <Visibility />
                                </IconButton>
                                <IconButton component="a" href={doc.url} download>
                                  <Download />
                                </IconButton>
                              </div>
                            ))
                          ) : (
                            "-"
                          )}
                        </TableCell>
                      )}
                    </>
                  )}
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </Paper>
      )}
    </div>
  );
}
